return items.map(item => {
  const d = item.json;

  const normalizeText = (v) => {
    if (v === null || v === undefined) return '';
    return String(v).trim();
  };

  const normalizeName = (v) => {
    const name = normalizeText(v).replace(/\u3000/g, ' ');
    if (!name) return '';

    if (/^[A-Za-z\s]+$/.test(name)) return name;

    const parts = name.split(/\s+/).filter(Boolean);
    if (parts.length >= 2) {
      return `${parts[0]}、${parts.slice(1).join(' ')}`;
    }
    return name;
  };

  const normalizePhone = (v) => {
    return normalizeText(v).replace(/[^0-9]/g, '');
  };

  const normalizePostalCode = (v) => {
    return normalizeText(v).replace(/[^0-9]/g, '');
  };

  const normalizeGender = (v) => {
    const val = normalizeText(v).toLowerCase();

    if (['m', 'male', 'man', '男', '男性'].includes(val)) return 'Male';
    if (['f', 'female', 'woman', '女', '女性'].includes(val)) return 'Female';

    return 'NON';
  };

  const normalizeDate = (v) => {
    const raw = normalizeText(v);
    if (!raw) return '';

    const dt = new Date(raw);
    if (isNaN(dt.getTime())) return '';

    const y = dt.getFullYear();
    const m = String(dt.getMonth() + 1).padStart(2, '0');
    const d2 = String(dt.getDate()).padStart(2, '0');

    return `${y}/${m}/${d2}`;
  };

  const splitAddress = (prefectureValue, addressValue) => {
    const merged = normalizeText(prefectureValue) + normalizeText(addressValue);

    if (!merged) {
      return { prefecture: '', address: '' };
    }

    const prefectures = [
      '北海道',
      '青森県','岩手県','宮城県','秋田県','山形県','福島県',
      '茨城県','栃木県','群馬県','埼玉県','千葉県','東京都','神奈川県',
      '新潟県','富山県','石川県','福井県','山梨県','長野県',
      '岐阜県','静岡県','愛知県','三重県',
      '滋賀県','京都府','大阪府','兵庫県','奈良県','和歌山県',
      '鳥取県','島根県','岡山県','広島県','山口県',
      '徳島県','香川県','愛媛県','高知県',
      '福岡県','佐賀県','長崎県','熊本県','大分県','宮崎県','鹿児島県',
      '沖縄県'
    ];

    for (const p of prefectures) {
      if (merged.startsWith(p)) {
        return {
          prefecture: p,
          address: merged.slice(p.length).trim()
        };
      }
    }

    return {
      prefecture: normalizeText(prefectureValue),
      address: normalizeText(addressValue)
    };
  };

  // 元データ
  const sourceName = d.raw_name;
  const sourceEmail = d.raw_email;
  const sourcePhone = d.raw_phone;
  const sourcePrefecture = d.raw_prefecture;
  const sourceAddress = d.address || d.city || '';
  const sourceGender = d.raw_gender;
  const sourceBirthDate = d.birth_date;
  const sourceImportedAt = d.created_at;
  const sourcePostalCode = d.postal_code;

  // 正規化
  d.name = normalizeName(sourceName);
  d.email = normalizeText(sourceEmail);
  d.phone = normalizePhone(sourcePhone);
  d.gender = normalizeGender(sourceGender);

  const addr = splitAddress(sourcePrefecture, sourceAddress);
  d.prefecture = addr.prefecture;
  d.address = addr.address;

  d.postal_code = normalizePostalCode(sourcePostalCode);
  d.birth_date = normalizeDate(sourceBirthDate);
  d.imported_at = normalizeDate(sourceImportedAt);
  d.source = normalizeText(d.source);

  // レビュー理由
  const reasons = [];
  if (!d.name) reasons.push('Missing name');
  if (!d.email) reasons.push('Missing email');
  if (!d.phone) reasons.push('Missing phone');
  if (!d.prefecture) reasons.push('Missing prefecture');
  if (!d.address) reasons.push('Missing address');
  if (!d.birth_date) reasons.push('Invalid birth date');

  d.review_reason = reasons.join(' / ');

  // スコア: addressも必須にする
  const completenessScore =
    (d.name ? 17 : 0) +
    (d.email ? 17 : 0) +
    (d.phone ? 17 : 0) +
    (d.prefecture ? 17 : 0) +
    (d.address ? 16 : 0) +
    (d.birth_date ? 16 : 0);

  d.completeness_score = completenessScore;

  // 必須項目が全部あるときだけ normalized
  const isValid =
    !!d.name &&
    !!d.email &&
    !!d.phone &&
    !!d.prefecture &&
    !!d.address &&
    !!d.birth_date;

  d.status = isValid ? 'normalized' : 'needs_review';
  d.record_key = `${d.source}_${d.imported_at}`;

  return { json: d };
});

const itemsIn = $input.all();

// review_queue の sheetId を入れる
const sheetId = 1144211222;

const colMap = {
  name: 1,               // B
  email: 2,              // C
  phone: 3,              // D
  postal_code: 4,        // E
  prefecture: 5,         // F
  address: 6,            // G
  gender: 7,             // H
  birth_date: 8,         // I
  source: 9,             // J
  imported_at: 10,       // K
  completeness_score: 11,// L
  status: 12,            // M
  review_reason: 13,     // N
  record_key: 14         // O
};

// 空欄チェックしたい列
const targetFields = [
  'name',
  'email',
  'phone',
  'postal_code',
  'prefecture',
  'address',
  'gender',
  'birth_date',
  'source',
  'imported_at'
];

const requests = [];

for (let i = 0; i < itemsIn.length; i++) {
  const d = itemsIn[i].json;

  // シートの実行結果2行目から始まる想定
  const rowIndex = i + 1;

  for (const field of targetFields) {
    const value = d[field];

    const isEmpty =
      value === null ||
      value === undefined ||
      String(value).trim() === '';

    if (isEmpty) {
      const colIndex = colMap[field];

      requests.push({
        repeatCell: {
          range: {
            sheetId,
            startRowIndex: rowIndex,
            endRowIndex: rowIndex + 1,
            startColumnIndex: colIndex,
            endColumnIndex: colIndex + 1
          },
          cell: {
            userEnteredFormat: {
              backgroundColor: {
                red: 1,
                green: 0.9,
                blue: 0.9
              }
            }
          },
          fields: 'userEnteredFormat.backgroundColor'
        }
      });
    }
  }
}

return [
  {
    json: {
      spreadsheetId: 'YOUR_SPREADSHEET_ID',
      requests
    }
  }
];

